sys_transform_script.script:
(function runTransformScript(source, map, log, target /*undefined onStart*/ ) {

    var attributeValue = source.u_attributevalue;

    if (JSUtil.nil(attributeValue)) {
        ignore = true;
        return;
    }

    attributeValue = attributeValue.toString().trim().toLowerCase();


    var assetId = source.u_external_id__c;

    if (JSUtil.nil(assetId)) {
        ignore = true;
        return;
    }

    var contractItemGr = new GlideRecord("sn_customerservice_contract_item");
    contractItemGr.addQuery("u_siebel_asset_number", assetId);
    contractItemGr.setLimit(1);
    contractItemGr.query();

    if (!contractItemGr.next()) {
        ignore = true;
        return;
    }

    var product = contractItemGr.getValue("u_product");

    if (JSUtil.nil(product)) {
        ignore = true;
        return;
    }

    var attributeGr = new GlideRecord("u_managed_service_attribute");
    attributeGr.addQuery("u_managed_service", product);
    attributeGr.addQuery("u_key", source.u_attributename);
    attributeGr.setLimit(1);
    attributeGr.query();

    if (!attributeGr.next()) {
        ignore = true;
    }

})(source, map, log, target);
